#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long x;
        scanf("%lld", &x);
        if (x == 404404404LL) {
            printf("NOT FOUND\n");
        } else {
            printf("FOUND\n");
        }
    }
    return 0;
}

