#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        code = data[i]
        if code == "404404404":
            out.append("NOT FOUND")
        else:
            out.append("FOUND")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

